#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char S[100005];
        scanf("%s", S);
        int first = -1, last = -1;
        for (int i = 0; i < strlen(S); i++) {
            if (S[i] == '1') {
                if (first == -1) first = i;
                last = i;
            }
        }
        if (first == -1) printf("NO\n");
        else {
            int valid = 1;
            for (int i = first; i <= last; i++) {
                if (S[i] == '0') {
                    valid = 0;
                    break;
                }
            }
            if (valid) printf("YES\n");
            else printf("NO\n");
        }
    }
    return 0;
}

